const body = $input.first()?.json?.body || $input.first()?.json || {};
const required = ['event_id', 'idempotency_key', 'amount_paid'];
const missing = required.filter((key) => body[key] === undefined || body[key] === null || body[key] === '');
const paymentConfirmed = body.payment_confirmed === true;
return [{ json: { ...body, payment_confirmed: paymentConfirmed, missing_required: missing, confirmation_valid: paymentConfirmed && missing.length === 0 } }];
